// JsonTree.tsx
import { useState } from 'react';
export function JsonTree({ value, onEdit }: { value: unknown; onEdit?: (path: ReadonlyArray<string | number>, newValue: unknown) => void }) {
  const [focusedPath, setFocusedPath] = useState<ReadonlyArray<string | number>>([]);
  const [expanded, setExpanded] = useState<Set<string>>(new Set(['']));
  const pathKey = (p: ReadonlyArray<string | number>) => p.join('.');
  return (
    <div className="font-mono text-[12.5px]">
      <div className="px-3 py-1.5 bg-[oklch(0.97_0.005_250)] border-b border-[oklch(0.92_0.005_250)] text-[11px] text-[oklch(0.55_0.005_250)] truncate">{focusedPath.length ? `root.${focusedPath.join('.')}` : 'root'}</div>
      <Node value={value} path={[]} expanded={expanded} setExpanded={setExpanded} focusedPath={focusedPath} setFocusedPath={setFocusedPath} pathKey={pathKey} onEdit={onEdit} />
    </div>
  );
}
function Node({ value, path, expanded, setExpanded, focusedPath, setFocusedPath, pathKey, onEdit }: any): React.ReactNode {
  const key = pathKey(path);
  const isExpanded = expanded.has(key);
  const isFocused = pathKey(focusedPath) === key;
  const onClick = () => setFocusedPath(path);
  if (value === null || value === undefined) return <div onClick={onClick} className={`pl-${path.length * 4} px-2 ${isFocused ? 'bg-[oklch(0.94_0.04_250)]' : ''}`}><span style={{ color: 'oklch(0.6 0.005 250)' }}>null</span></div>;
  if (Array.isArray(value)) return (<div>
    <div onClick={() => setExpanded((e: Set<string>) => { const n = new Set(e); if (n.has(key)) n.delete(key); else n.add(key); return n; })} className={`px-2 cursor-pointer ${isFocused ? 'bg-[oklch(0.94_0.04_250)]' : ''}`} style={{ paddingLeft: 8 + path.length * 16 }}><span className="text-[oklch(0.55_0.005_250)]">{isExpanded ? '\u25BE' : '\u25B8'}</span> [{value.length}]</div>
    {isExpanded && value.map((v, i) => <Node key={i} value={v} path={[...path, i]} {...{ expanded, setExpanded, focusedPath, setFocusedPath, pathKey, onEdit }} />)}
  </div>);
  if (typeof value === 'object') { const entries = Object.entries(value); return (<div>
    <div onClick={() => setExpanded((e: Set<string>) => { const n = new Set(e); if (n.has(key)) n.delete(key); else n.add(key); return n; })} className={`px-2 cursor-pointer ${isFocused ? 'bg-[oklch(0.94_0.04_250)]' : ''}`} style={{ paddingLeft: 8 + path.length * 16 }}><span className="text-[oklch(0.55_0.005_250)]">{isExpanded ? '\u25BE' : '\u25B8'}</span> {`{${entries.length}}`}</div>
    {isExpanded && entries.map(([k, v]) => (<div key={k}><div className="px-2" style={{ paddingLeft: 8 + (path.length + 1) * 16, color: 'oklch(0.4 0.04 250)' }}>{k}:</div><Node value={v} path={[...path, k]} {...{ expanded, setExpanded, focusedPath, setFocusedPath, pathKey, onEdit }} /></div>))}
  </div>);
  }
  const valueColor = typeof value === 'string' ? 'oklch(0.5 0.14 25)' : typeof value === 'number' ? 'oklch(0.45 0.16 145)' : typeof value === 'boolean' ? 'oklch(0.55 0.16 280)' : 'oklch(0.6 0.005 250)';
  return <div onClick={onClick} className={`px-2 ${isFocused ? 'bg-[oklch(0.94_0.04_250)]' : ''}`} style={{ paddingLeft: 8 + path.length * 16 }}><span style={{ color: valueColor }}>{typeof value === 'string' ? `\"${value}\"` : String(value)}</span></div>;
}

