import { useState, useRef } from 'react';
export function TagInput({ value, onChange, placeholder }: { value: ReadonlyArray<string>; onChange: (tags: ReadonlyArray<string>) => void; placeholder?: string }) {
  const [input, setInput] = useState('');
  const inputRef = useRef<HTMLInputElement | null>(null);
  const addTag = (raw: string) => { const tag = raw.trim(); if (tag && !value.includes(tag)) onChange([...value, tag]); };
  const onKey = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ',') { e.preventDefault(); addTag(input); setInput(''); }
    else if (e.key === 'Backspace' && input === '' && value.length > 0) onChange(value.slice(0, -1));
  };
  const onPaste = (e: React.ClipboardEvent) => {
    const text = e.clipboardData.getData('text');
    if (text.includes(',')) { e.preventDefault(); const parts = text.split(',').map(p => p.trim()).filter(Boolean); onChange([...value, ...parts.filter(p => !value.includes(p))]); }
  };
  return (
    <div className="flex flex-wrap items-center gap-1 min-h-10 px-2 py-1 border border-[oklch(0.85_0.005_250)] rounded-md focus-within:border-[oklch(0.55_0.18_250)]" onClick={() => inputRef.current?.focus()}>
      {value.map((tag, i) => (
        <span key={i} className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] bg-[oklch(0.95_0.005_250)] text-[oklch(0.3_0.005_250)] rounded-md" style={{ animation: 'chipIn 80ms ease-out' }}>
          {tag}
          <button type="button" onClick={() => onChange(value.filter((_, j) => j !== i))} aria-label={`Remove ${tag}`} className="text-[10px] opacity-60 hover:opacity-100">\u00D7</button>
        </span>
      ))}
      <input ref={inputRef} value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={onKey} onPaste={onPaste} placeholder={value.length === 0 ? placeholder : ''} aria-label="Add tag" className="flex-1 min-w-[80px] outline-none text-[14px] bg-transparent" />
      <style>{`@keyframes chipIn { from { opacity: 0; transform: scale(0.85) } to { opacity: 1; transform: scale(1) } } @media (prefers-reduced-motion: reduce) { [style*='chipIn'] { animation: none !important } }`}</style>
    </div>
  );
}

