import { useState, useRef } from 'react';
export function PullToRefresh({ onRefresh, children }: { onRefresh: () => Promise<void>; children: React.ReactNode }) {
  const [pullDistance, setPullDistance] = useState(0);
  const [refreshing, setRefreshing] = useState(false);
  const startY = useRef<number | null>(null);
  const threshold = 80;
  const armed = pullDistance >= threshold;
  const onTouchStart = (e: React.TouchEvent) => { if (window.scrollY === 0) startY.current = e.touches[0].clientY; };
  const onTouchMove = (e: React.TouchEvent) => {
    if (startY.current === null) return;
    const dy = e.touches[0].clientY - startY.current;
    if (dy <= 0) { setPullDistance(0); return; }
    const resisted = dy < 60 ? dy : 60 + (dy - 60) * 0.4;
    setPullDistance(resisted);
  };
  const onTouchEnd = async () => {
    if (armed && !refreshing) {
      setRefreshing(true);
      try { await onRefresh(); } finally { setRefreshing(false); setPullDistance(0); startY.current = null; }
    } else {
      setPullDistance(0); startY.current = null;
    }
  };
  return (
    <div onTouchStart={onTouchStart} onTouchMove={onTouchMove} onTouchEnd={onTouchEnd}>
      <div className="flex items-center justify-center overflow-hidden" style={{ height: pullDistance, transition: startY.current ? 'none' : 'height 200ms ease-out' }}>
        <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" style={{ animation: refreshing ? 'spin 800ms linear infinite' : undefined }}>
          <circle cx="12" cy="12" r="10" stroke="oklch(0.55 0.18 250)" strokeWidth="2" fill={armed ? 'oklch(0.55 0.18 250 / 0.2)' : 'none'} strokeDasharray={refreshing ? '20 40' : undefined} />
        </svg>
      </div>
      {children}
      <style>{`@keyframes spin { to { transform: rotate(360deg) } } @media (prefers-reduced-motion: reduce) { [style*='spin'] { animation: none !important } }`}</style>
    </div>
  );
}

