import { useState } from 'react';
export interface SankeyNode { id: string; label: string; stage: number; }
export interface SankeyFlow { fromId: string; toId: string; value: number; }
export function Sankey({ nodes, flows }: { nodes: ReadonlyArray<SankeyNode>; flows: ReadonlyArray<SankeyFlow> }) {
  const [hoverNode, setHoverNode] = useState<string | null>(null);
  const isInPath = (flow: SankeyFlow) => !hoverNode || flow.fromId === hoverNode || flow.toId === hoverNode || tracePath(flow, hoverNode);
  function tracePath(_flow: SankeyFlow, _root: string): boolean { return false; /* full impl: traverse downstream/upstream from root */ }
  // Simplified layout (real impl uses d3-sankey)
  const stages = Array.from(new Set(nodes.map(n => n.stage))).sort();
  const stageW = 720 / (stages.length + 1);
  const nodesByStage = stages.map(s => nodes.filter(n => n.stage === s));
  return (
    <svg width={720} height={480}>
      {flows.map((f, i) => {
        const fromNode = nodes.find(n => n.id === f.fromId)!;
        const toNode = nodes.find(n => n.id === f.toId)!;
        const x1 = fromNode.stage * stageW + 20;
        const x2 = toNode.stage * stageW + 20;
        const y1 = 240 + (i % 5 - 2) * 30;
        const y2 = 240 + (i % 7 - 3) * 30;
        return <path key={i} d={`M${x1} ${y1} C${x1 + 100} ${y1}, ${x2 - 100} ${y2}, ${x2} ${y2}`} stroke="oklch(0.55 0.18 250)" strokeWidth={Math.max(2, f.value / 50)} fill="none" style={{ opacity: isInPath(f) ? 0.6 : 0.2, transition: 'opacity 150ms ease-out' }} />;
      })}
      {nodes.map(n => (
        <g key={n.id} onMouseEnter={() => setHoverNode(n.id)} onMouseLeave={() => setHoverNode(null)}>
          <rect x={n.stage * stageW + 10} y={200 + (parseInt(n.id) % 5) * 40} width={20} height={32} fill="oklch(0.2 0.01 250)" style={{ opacity: !hoverNode || hoverNode === n.id ? 1 : 0.3 }} />
          <text x={n.stage * stageW + 36} y={220 + (parseInt(n.id) % 5) * 40} fontSize="12" fill="oklch(0.2 0.01 250)">{n.label}</text>
        </g>
      ))}
    </svg>
  );
}

