import { useState } from 'react';
export function PermissionRequest({ kind, rationale, onGranted }: { kind: 'camera' | 'microphone' | 'notifications'; rationale: string; onGranted: () => void }) {
  const [state, setState] = useState<'idle' | 'denied'>('idle');
  const request = async () => {
    try {
      if (kind === 'camera') await navigator.mediaDevices.getUserMedia({ video: true });
      else if (kind === 'microphone') await navigator.mediaDevices.getUserMedia({ audio: true });
      else if (kind === 'notifications') { const perm = await Notification.requestPermission(); if (perm !== 'granted') throw new Error('denied'); }
      onGranted();
    } catch { setState('denied'); }
  };
  if (state === 'denied') return (
    <div className="bg-[oklch(0.95_0.04_25)] border border-[oklch(0.85_0.16_25)] p-3 rounded-md text-[13px]">
      <div className="font-medium mb-1">Permission denied</div>
      <p className="text-[12px] text-[oklch(0.4_0.005_250)]">{kind} access was blocked. Open browser settings to allow it for this site.</p>
    </div>
  );
  return (
    <div className="bg-[oklch(0.97_0.005_250)] border border-[oklch(0.92_0.005_250)] p-3 rounded-md" style={{ animation: 'permIn 200ms ease-out' }}>
      <p className="text-[14px] mb-2">{rationale}</p>
      <button type="button" onClick={request} className="text-[13px] bg-[oklch(0.55_0.18_250)] text-white px-3 py-1.5 rounded">Continue</button>
      <style>{`@keyframes permIn { from { opacity: 0; transform: translateY(-4px) } to { opacity: 1; transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='permIn'] { animation: none !important } }`}</style>
    </div>
  );
}

// PasswordInput.tsx
import { useState, useMemo } from 'react';
const DEFAULT_RULES = [
  { label: 'At least 8 characters', test: (v: string) => v.length >= 8 },
  { label: 'One uppercase letter', test: (v: string) => /[A-Z]/.test(v) },
  { label: 'One number', test: (v: string) => /\d/.test(v) },
  { label: 'One symbol', test: (v: string) => /[^a-zA-Z0-9]/.test(v) },
];
export function PasswordInput({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  const [show, setShow] = useState(false);
  const passed = useMemo(() => DEFAULT_RULES.map(r => r.test(value)), [value]);
  const score = passed.filter(Boolean).length;
  const strengthColor = score < 2 ? 'oklch(0.6 0.18 25)' : score < 4 ? 'oklch(0.7 0.16 80)' : 'oklch(0.55 0.14 145)';
  return (
    <div>
      <div className="relative">
        <input type={show ? 'text' : 'password'} value={value} onChange={(e) => onChange(e.target.value)} aria-label="Password" aria-describedby="pw-strength pw-rules" className="w-full h-9 px-3 pr-10 border border-[oklch(0.85_0.005_250)] rounded-md outline-none focus:border-[oklch(0.55_0.18_250)]" />
        <button type="button" onClick={() => setShow(s => !s)} aria-label={show ? 'Hide password' : 'Show password'} className="absolute top-2 right-2 text-[11px] text-[oklch(0.55_0.005_250)] hover:text-[oklch(0.2_0.01_250)]">{show ? 'Hide' : 'Show'}</button>
      </div>
      <div id="pw-strength" className="mt-2 flex gap-1" aria-label=`Strength: ${score} of ${DEFAULT_RULES.length}`>
        {Array.from({ length: DEFAULT_RULES.length }).map((_, i) => <div key={i} className="h-0.5 flex-1 rounded" style={{ background: i < score ? strengthColor : 'oklch(0.93 0.005 250)', transition: 'background 200ms ease-out' }} />)}
      </div>
      <ul id="pw-rules" className="mt-2 space-y-1">
        {DEFAULT_RULES.map((r, i) => (
          <li key={r.label} className="flex items-center gap-2 text-[12px]" style={{ color: passed[i] ? 'oklch(0.45 0.14 145)' : 'oklch(0.55 0.005 250)' }}>
            <svg width="12" height="12" viewBox="0 0 12 12" aria-hidden="true" style={{ transition: 'fill 150ms ease-out' }}><circle cx="6" cy="6" r="5" stroke="currentColor" strokeWidth="1.5" fill={passed[i] ? 'currentColor' : 'transparent'} />{passed[i] && <path d="M3.5 6 L5.5 8 L8.5 4" stroke="white" strokeWidth="1.5" fill="none" />}</svg>
            {r.label}
          </li>
        ))}
      </ul>
    </div>
  );
}

