import { useState } from 'react';
import { useInputModality } from './useInputModality';
export function FilterPill({ label, options, selected, onChange }: { label: string; options: ReadonlyArray<string>; selected: ReadonlyArray<string>; onChange: (next: ReadonlyArray<string>) => void }) {
  const modality = useInputModality();
  const [open, setOpen] = useState(false);
  const labelText = selected.length === 0 ? label : selected.length === 1 ? selected[0] : `${label} (${selected.length})`;
  const toggle = (opt: string) => onChange(selected.includes(opt) ? selected.filter(s => s !== opt) : [...selected, opt]);
  return (
    <>
      <button type="button" onClick={() => setOpen(o => !o)} className={`h-8 px-3 text-[13px] font-medium rounded-full ${selected.length > 0 ? 'bg-[oklch(0.94_0.04_250)] text-[oklch(0.3_0.04_250)]' : 'bg-[oklch(0.95_0.005_250)] text-[oklch(0.3_0.005_250)]'}`}>{labelText}</button>
      {open && modality === 'mouse' && (
        <div className="absolute mt-1 bg-white border border-[oklch(0.92_0.005_250)] rounded-md shadow-lg p-2 z-10">
          {options.map(opt => <label key={opt} className="flex items-center gap-2 px-2 py-1 text-[13px] hover:bg-[oklch(0.97_0.005_250)] cursor-pointer"><input type="checkbox" checked={selected.includes(opt)} onChange={() => toggle(opt)} />{opt}</label>)}
          <button type="button" onClick={() => onChange([])} className="w-full mt-2 text-[12px] text-[oklch(0.55_0.005_250)] py-1">Reset</button>
        </div>
      )}
      {open && modality === 'touch' && (
        <div className="fixed inset-0 z-50 flex items-end" onClick={() => setOpen(false)}>
          <div className="absolute inset-0 bg-black/30" />
          <div className="relative w-full bg-white rounded-t-2xl p-4" onClick={(e) => e.stopPropagation()} style={{ height: '50vh', animation: 'sheetIn 300ms cubic-bezier(0.32, 0.72, 0, 1)' }}>
            <div className="flex justify-center pb-3"><div className="w-10 h-1 bg-[oklch(0.85_0.005_250)] rounded-full" /></div>
            <h3 className="text-[15px] font-medium mb-3">{label}</h3>
            <ul className="overflow-y-auto" style={{ maxHeight: 'calc(50vh - 120px)' }}>{options.map(opt => <li key={opt}><label className="flex items-center gap-3 py-3 text-[17px] border-b border-[oklch(0.95_0.005_250)]"><input type="checkbox" checked={selected.includes(opt)} onChange={() => toggle(opt)} className="w-5 h-5" />{opt}</label></li>)}</ul>
            <button type="button" onClick={() => onChange([])} className="mt-3 text-[14px] text-[oklch(0.55_0.18_250)]">Reset</button>
            <style>{`@keyframes sheetIn { from { transform: translateY(100%) } to { transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='sheetIn'] { animation: none !important } }`}</style>
          </div>
        </div>
      )}
    </>
  );
}

// Tabs.tsx
import { useId, useState, useRef } from 'react';
export function Tabs({ tabs, defaultActiveId }: { tabs: ReadonlyArray<{ id: string; label: string; content: React.ReactNode }>; defaultActiveId?: string }) {
  const baseId = useId();
  const [activeId, setActiveId] = useState(defaultActiveId ?? tabs[0]?.id);
  const [focusedIdx, setFocusedIdx] = useState(0);
  const tabsRef = useRef<HTMLButtonElement[]>([]);
  const onKey = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowRight') { e.preventDefault(); const next = Math.min(tabs.length - 1, focusedIdx + 1); setFocusedIdx(next); tabsRef.current[next]?.focus(); }
    else if (e.key === 'ArrowLeft') { e.preventDefault(); const next = Math.max(0, focusedIdx - 1); setFocusedIdx(next); tabsRef.current[next]?.focus(); }
    else if (e.key === 'Home') { e.preventDefault(); setFocusedIdx(0); tabsRef.current[0]?.focus(); }
    else if (e.key === 'End') { e.preventDefault(); setFocusedIdx(tabs.length - 1); tabsRef.current[tabs.length - 1]?.focus(); }
    else if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setActiveId(tabs[focusedIdx].id); }
  };
  return (
    <div>
      <div role="tablist" className="flex border-b border-[oklch(0.92_0.005_250)]" onKeyDown={onKey}>
        {tabs.map((t, i) => (
          <button key={t.id} ref={(el) => { if (el) tabsRef.current[i] = el; }} type="button" role="tab" id={`${baseId}-tab-${t.id}`} aria-selected={t.id === activeId} aria-controls={`${baseId}-panel-${t.id}`} tabIndex={i === focusedIdx ? 0 : -1}
            onClick={() => { setActiveId(t.id); setFocusedIdx(i); }}
            className={`h-10 px-3 text-[14px] font-medium border-b-2 ${t.id === activeId ? 'border-[oklch(0.55_0.18_250)] text-[oklch(0.2_0.01_250)]' : 'border-transparent text-[oklch(0.55_0.005_250)] hover:text-[oklch(0.3_0.005_250)]'} focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-[-2px] focus-visible:outline-[oklch(0.55_0.18_250)]`}>
            {t.label}
          </button>
        ))}
      </div>
      {tabs.map(t => (
        <div key={t.id} role="tabpanel" id={`${baseId}-panel-${t.id}`} aria-labelledby={`${baseId}-tab-${t.id}`} hidden={t.id !== activeId} className="p-4">{t.content}</div>
      ))}
    </div>
  );
}

