// SettingsSearch.tsx
import { useState, useMemo } from 'react';
export interface SettingIndex { categoryId: string; categoryLabel: string; settingId: string; settingLabel: string; description: string; tags: ReadonlyArray<string>; }
export function SettingsSearch({ index, onNavigate, open, onClose }: { index: ReadonlyArray<SettingIndex>; onNavigate: (categoryId: string, settingId: string) => void; open: boolean; onClose: () => void }) {
  const [query, setQuery] = useState('');
  const [focusedIdx, setFocusedIdx] = useState(0);
  const results = useMemo(() => { const q = query.toLowerCase(); if (!q) return []; return index.filter(i => i.settingLabel.toLowerCase().includes(q) || i.description.toLowerCase().includes(q) || i.tags.some(t => t.toLowerCase().includes(q))).slice(0, 8); }, [index, query]);
  if (!open) return null;
  return (
    <div role="dialog" aria-label="Search settings" className="fixed inset-0 z-50 flex items-start justify-center pt-[15vh] bg-black/50" onClick={onClose}>
      <div onClick={(e) => e.stopPropagation()} className="w-[480px] bg-white rounded-lg shadow-2xl overflow-hidden">
        <input autoFocus value={query} onChange={(e) => { setQuery(e.target.value); setFocusedIdx(0); }} onKeyDown={(e) => {
          if (e.key === 'ArrowDown') { e.preventDefault(); setFocusedIdx(i => Math.min(results.length - 1, i + 1)); }
          else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusedIdx(i => Math.max(0, i - 1)); }
          else if (e.key === 'Enter') { e.preventDefault(); const r = results[focusedIdx]; if (r) { onNavigate(r.categoryId, r.settingId); onClose(); } }
        }} placeholder="Search settings\u2026" className="w-full h-12 px-4 text-[15px] outline-none border-b border-[oklch(0.93_0.005_250)]" />
        <ul role="listbox">{results.map((r, i) => (
          <li key={`${r.categoryId}.${r.settingId}`} role="option" aria-selected={i === focusedIdx} onClick={() => { onNavigate(r.categoryId, r.settingId); onClose(); }} className={`px-4 py-2 cursor-pointer ${i === focusedIdx ? 'bg-[oklch(0.94_0.04_250)]' : ''}`}>
            <div className="text-[13px] font-medium">{r.settingLabel}</div>
            <div className="text-[11px] text-[oklch(0.55_0.005_250)]">{r.categoryLabel}</div>
          </li>
        ))}</ul>
      </div>
    </div>
  );
}

