// useForceLayout.ts (concept)
export function useForceLayout(nodes: ReadonlyArray<{ id: string }>, edges: ReadonlyArray<{ source: string; target: string }>) {
  // In real impl: run d3-force simulation for 200 ticks, freeze.
  return nodes.map((n, i) => ({ id: n.id, x: Math.cos((i / nodes.length) * Math.PI * 2) * 200 + 400, y: Math.sin((i / nodes.length) * Math.PI * 2) * 200 + 300 }));
}
// NetworkGraph.tsx
import { useState, useMemo } from 'react';
export function NetworkGraph({ nodes, edges }: { nodes: ReadonlyArray<{ id: string; label: string }>; edges: ReadonlyArray<{ source: string; target: string }> }) {
  const positions = useForceLayout(nodes, edges);
  const [focusId, setFocusId] = useState<string | null>(null);
  const neighbors = useMemo(() => { if (!focusId) return new Set<string>(); const n = new Set<string>(); for (const e of edges) { if (e.source === focusId) n.add(e.target); if (e.target === focusId) n.add(e.source); } return n; }, [focusId, edges]);
  return (
    <svg viewBox="0 0 800 600" className="w-full h-full">
      {edges.map((e, i) => { const s = positions.find(p => p.id === e.source)!; const t = positions.find(p => p.id === e.target)!; const dim = focusId && focusId !== e.source && focusId !== e.target; return <line key={i} x1={s.x} y1={s.y} x2={t.x} y2={t.y} stroke="oklch(0.7 0.005 250)" strokeWidth="1" style={{ opacity: dim ? 0.2 : 0.6, transition: 'opacity 200ms ease-out' }} />; })}
      {nodes.map(n => { const pos = positions.find(p => p.id === n.id)!; const isFocus = focusId === n.id; const isNeighbor = neighbors.has(n.id); const dim = focusId && !isFocus && !isNeighbor; return (
        <g key={n.id} transform={`translate(${pos.x},${pos.y})`} onClick={() => setFocusId(f => f === n.id ? null : n.id)} className="cursor-pointer" style={{ opacity: dim ? 0.2 : 1, transition: 'opacity 200ms ease-out' }}>
          <circle r={isFocus ? 10 : 6} fill="oklch(0.55 0.18 250)" />
          <text x={10} y={4} fontSize="11" fill="oklch(0.2 0.01 250)">{n.label}</text>
        </g>
      ); })}
    </svg>
  );
}

