// detectBrand.ts
export function detectBrand(digits: string): 'visa' | 'mastercard' | 'amex' | 'discover' | null {
  if (digits.startsWith('4')) return 'visa';
  if (/^5[1-5]/.test(digits) || /^2[2-7]/.test(digits)) return 'mastercard';
  if (/^3[47]/.test(digits)) return 'amex';
  if (/^6/.test(digits)) return 'discover';
  return null;
}
export function formatCard(digits: string, brand: ReturnType<typeof detectBrand>): string {
  if (brand === 'amex') return `${digits.slice(0,4)} ${digits.slice(4,10)} ${digits.slice(10,15)}`.trim();
  return digits.match(/.{1,4}/g)?.join(' ') ?? digits;
}
