// TiltCard.tsx
import { useRef, useState } from 'react';
export function TiltCard({ bgImage, title, subtitle }: { bgImage: string; title: string; subtitle: string }) {
  const ref = useRef<HTMLDivElement | null>(null);
  const [tilt, setTilt] = useState({ x: 0, y: 0 });
  const onMove = (e: React.MouseEvent) => {
    const el = ref.current; if (!el) return;
    const r = el.getBoundingClientRect();
    const px = (e.clientX - r.left) / r.width - 0.5;
    const py = (e.clientY - r.top) / r.height - 0.5;
    setTilt({ x: -py * 8, y: px * 8 });
  };
  return (
    <div ref={ref} onMouseMove={onMove} onMouseLeave={() => setTilt({ x: 0, y: 0 })} className="relative w-80 h-[420px] rounded-lg overflow-hidden cursor-pointer" style={{ transform: `perspective(800px) rotateX(${tilt.x}deg) rotateY(${tilt.y}deg)`, transition: tilt.x === 0 && tilt.y === 0 ? 'transform 400ms cubic-bezier(0.22, 1, 0.36, 1)' : 'none', transformStyle: 'preserve-3d' }}>
      <div className="absolute inset-0 bg-cover bg-center" style={{ backgroundImage: `url(${bgImage})`, transform: `translateZ(-20px) scale(1.1)` }} />
      <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent" />
      <div className="absolute bottom-0 left-0 right-0 p-4 text-white" style={{ transform: 'translateZ(20px)' }}>
        <div className="text-[18px] font-medium">{title}</div>
        <div className="text-[12px] opacity-80">{subtitle}</div>
      </div>
    </div>
  );
}

