// Disclosure.tsx
import { useEffect, useRef, useState } from 'react';
export function Disclosure({ trigger, children, defaultOpen = false }: { trigger: React.ReactNode; children: React.ReactNode; defaultOpen?: boolean }) {
  const [open, setOpen] = useState(defaultOpen);
  const contentRef = useRef<HTMLDivElement | null>(null);
  const [height, setHeight] = useState(defaultOpen ? 'auto' : '0px');
  useEffect(() => {
    const el = contentRef.current; if (!el) return;
    if (open) { setHeight(`${el.scrollHeight}px`); const t = window.setTimeout(() => setHeight('auto'), 250); return () => window.clearTimeout(t); }
    else { setHeight(`${el.scrollHeight}px`); requestAnimationFrame(() => setHeight('0px')); }
  }, [open]);
  return (
    <div>
      <button type="button" onClick={() => setOpen(o => !o)} aria-expanded={open} className="w-full flex items-center justify-between h-10 px-3 text-[14px] font-medium hover:bg-[oklch(0.97_0.005_250)]">
        {trigger}
        <span style={{ transform: open ? 'rotate(90deg)' : 'rotate(0)', transition: 'transform 200ms ease-out' }}>\u203A</span>
      </button>
      <div ref={contentRef} aria-hidden={!open} style={{ height, overflow: 'hidden', transition: 'height 250ms cubic-bezier(0.22, 1, 0.36, 1)' }}>
        <div className="p-3 text-[13px]">{children}</div>
      </div>
    </div>
  );
}

