    return () => clearTimeout(t);
  }, []);
  return (
    <div className="fixed inset-0 flex flex-col items-center justify-center" style={{ background: 'oklch(0.10 0.04 280)', fontFamily: "'Orbitron', 'Rajdhani', sans-serif" }}>
