      <div className="mt-8 w-80 h-1 bg-[oklch(0.20_0.04_280)]"><div className="h-full" style={{ width: `${progress * 100}%`, background: 'linear-gradient(90deg, oklch(0.7 0.18 200), oklch(0.65 0.22 320))', transition: 'width 200ms ease-out' }} /></div>
      <div className="mt-2 text-[11px] tabular-nums" style={{ color: 'oklch(0.7 0.18 200)' }}>{(progress * 100).toFixed(1)}%</div>
      <div aria-hidden="true" className="absolute inset-0 pointer-events-none" style={{ background: 'repeating-linear-gradient(0deg, transparent 0px, transparent 1px, oklch(0 0 0 / 0.08) 1px, oklch(0 0 0 / 0.08) 2px)' }} />
    </div>
  );
}

// BuildLog.tsx
import { useState } from 'react';
export interface Phase { id: string; name: string; status: 'success' | 'failed' | 'skipped' | 'running'; durationMs: number; lines: ReadonlyArray<string>; }
export function BuildLog({ phases }: { phases: ReadonlyArray<Phase> }) {
  const failed = phases.find(p => p.status === 'failed');
  const [expanded, setExpanded] = useState<Set<string>>(new Set(failed ? [failed.id] : []));
  return (
    <div>
      {failed && <button type="button" onClick={() => { setExpanded(e => new Set([...e, failed.id])); document.getElementById(`phase-${failed.id}`)?.scrollIntoView({ behavior: 'smooth' }); }} className="sticky top-0 z-10 w-full text-left px-3 py-2 bg-[oklch(0.95_0.04_25)] text-[oklch(0.4_0.16_25)] text-[12px] border-b border-[oklch(0.85_0.16_25)]">\u2193 Jump to failure</button>}
      {phases.map(p => (
        <div key={p.id} id={`phase-${p.id}`}>
          <button type="button" onClick={() => setExpanded(e => { const n = new Set(e); if (n.has(p.id)) n.delete(p.id); else n.add(p.id); return n; })} className="flex items-center w-full h-8 px-3 text-[13px] border-b border-[oklch(0.93_0.005_250)] hover:bg-[oklch(0.97_0.005_250)]">
            <StatusIcon status={p.status} />
            <span className="flex-1 ml-2 truncate text-left font-medium">{p.name}</span>
            <span className="text-[11px] tabular-nums text-[oklch(0.55_0.005_250)]">{(p.durationMs / 1000).toFixed(1)}s</span>
            <span className="ml-3 text-[oklch(0.55_0.005_250)]">{expanded.has(p.id) ? '\u25BE' : '\u25B8'}</span>
          </button>
          {expanded.has(p.id) && (
            <div className="bg-[oklch(0.16_0.005_250)] text-[oklch(0.85_0.005_250)] font-mono text-[12px] py-2 overflow-x-auto" style={{ animation: 'logExpand 200ms ease-out' }}>
              {p.lines.map((l, i) => <div key={i} className="px-3">{l}</div>)}
            </div>
          )}
        </div>
      ))}
      <style>{`@keyframes logExpand { from { opacity: 0; max-height: 0 } to { opacity: 1; max-height: 800px } } @media (prefers-reduced-motion: reduce) { [style*='logExpand'] { animation: none !important } }`}</style>
    </div>
  );
}
function StatusIcon({ status }: { status: Phase['status'] }) {
  if (status === 'success') return <span aria-label="success" className="w-3 h-3 rounded-full bg-[oklch(0.55_0.14_145)]" />;
  if (status === 'failed') return <span aria-label="failed" className="w-3 h-3 rounded-full bg-[oklch(0.6_0.18_25)]" />;
  if (status === 'running') return <span aria-label="running" className="w-3 h-3 rounded-full bg-[oklch(0.55_0.18_250)] animate-pulse" />;
  return <span aria-label="skipped" className="w-3 h-3 rounded-full bg-[oklch(0.85_0.005_250)]" />;
}

// KeyboardList.tsx
import { useState, useRef } from 'react';
export function KeyboardList<T extends { id: string }>({ items, renderItem, onOpen, shortcuts }: { items: ReadonlyArray<T>; renderItem: (item: T) => React.ReactNode; onOpen: (item: T) => void; shortcuts?: Record<string, (item: T) => void> }) {
  const [focusIdx, setFocusIdx] = useState(0);
  const containerRef = useRef<HTMLDivElement | null>(null);
  const onKey = (e: React.KeyboardEvent) => {
    if (e.key === 'j' || e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(items.length - 1, i + 1)); }
    else if (e.key === 'k' || e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); }
    else if (e.key === 'Enter' || e.key === 'o') { e.preventDefault(); if (items[focusIdx]) onOpen(items[focusIdx]); }
    else if (shortcuts && shortcuts[e.key]) { e.preventDefault(); shortcuts[e.key](items[focusIdx]); }
  };
  return (
    <div ref={containerRef} tabIndex={0} onKeyDown={onKey} role="listbox" aria-label="List" className="outline-none">
      {items.map((item, i) => (
        <div key={item.id} role="option" aria-selected={i === focusIdx} className={`flex items-center h-10 px-3 cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.97_0.005_250)]' : ''}`} style={{ borderLeft: i === focusIdx ? '2px solid oklch(0.55 0.18 250)' : '2px solid transparent' }} onClick={() => { setFocusIdx(i); onOpen(item); }}>
          {renderItem(item)}
        </div>
      ))}
    </div>
  );
}

// useUserStatus.ts
import { useEffect, useState, useRef } from 'react';
export type Status = 'active' | 'away' | 'busy' | 'offline';
export function useUserStatus(): { status: Status; setManualStatus: (s: Status | null) => void } {
  const [auto, setAuto] = useState<Status>('active');
  const [manual, setManual] = useState<{ status: Status; expiresAt: number } | null>(null);
  const lastInputRef = useRef(Date.now());
  useEffect(() => {
    const onInput = () => { lastInputRef.current = Date.now(); if (auto === 'away') setAuto('active'); };
    const onVisChange = () => { if (document.hidden) { const t = setTimeout(() => { if (document.hidden) setAuto('away'); }, 5 * 60 * 1000); return () => clearTimeout(t); } else { setAuto('active'); } };
    window.addEventListener('mousedown', onInput);
    window.addEventListener('keydown', onInput);
    document.addEventListener('visibilitychange', onVisChange);
    const idleCheck = setInterval(() => { if (Date.now() - lastInputRef.current > 10 * 60 * 1000) setAuto('away'); }, 30 * 1000);
    return () => { window.removeEventListener('mousedown', onInput); window.removeEventListener('keydown', onInput); document.removeEventListener('visibilitychange', onVisChange); clearInterval(idleCheck); };
  }, [auto]);
  const status: Status = manual && Date.now() < manual.expiresAt ? manual.status : auto;
  const setManualStatus = (s: Status | null) => setManual(s ? { status: s, expiresAt: Date.now() + 4 * 60 * 60 * 1000 } : null);
  return { status, setManualStatus };
}
