// CopyButton.tsx
import { useState, useRef, useEffect } from 'react';
export function CopyButton({ text, label = 'Copy' }: { text: string; label?: string }) {
  const [copied, setCopied] = useState(false);
  const timerRef = useRef<number | null>(null);
  useEffect(() => () => { if (timerRef.current) window.clearTimeout(timerRef.current); }, []);
  const onClick = async () => {
    try { await navigator.clipboard.writeText(text); setCopied(true); if (timerRef.current) window.clearTimeout(timerRef.current); timerRef.current = window.setTimeout(() => setCopied(false), 1500); } catch {}
  };
  return (
    <button type="button" onClick={onClick} aria-label={copied ? 'Copied' : label} className="inline-flex items-center justify-center w-7 h-7 rounded text-[oklch(0.55_0.005_250)] hover:bg-[oklch(0.95_0.005_250)] transition-colors duration-[150ms]" style={{ color: copied ? 'oklch(0.55 0.14 145)' : undefined }}>
      {copied ? <svg width="14" height="14" viewBox="0 0 14 14" aria-hidden="true"><path d="M3 7 L6 10 L11 4" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" /></svg> : <svg width="14" height="14" viewBox="0 0 14 14" aria-hidden="true"><rect x="3" y="3" width="8" height="8" rx="1" stroke="currentColor" strokeWidth="1.25" fill="none" /><rect x="5" y="5" width="6" height="6" rx="1" fill="currentColor" /></svg>}
    </button>
  );
}

// SparklineGrid.tsx
export interface SparkMetric { id: string; label: string; value: number; format: (v: number) => string; trend: ReadonlyArray<number>; delta: number; direction: 'up-is-good' | 'down-is-good'; }
export function SparklineGrid({ metrics, onClick }: { metrics: ReadonlyArray<SparkMetric>; onClick: (m: SparkMetric) => void }) {
  return (
    <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
      {metrics.map(m => {
        const min = Math.min(...m.trend), max = Math.max(...m.trend);
        const range = max - min || 1;
        const path = m.trend.map((v, i) => `${i ? 'L' : 'M'}${(i / (m.trend.length - 1) * 120).toFixed(1)} ${(40 - (v - min) / range * 40).toFixed(1)}`).join(' ');
        const isImprovement = (m.delta > 0 && m.direction === 'up-is-good') || (m.delta < 0 && m.direction === 'down-is-good');
        return (
          <button key={m.id} type="button" onClick={() => onClick(m)} className="text-left bg-white border border-[oklch(0.92_0.005_250)] rounded p-3 hover:bg-[oklch(0.97_0.005_250)]">
            <div className="flex items-baseline justify-between mb-2">
              <div className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)]">{m.label}</div>
              <div className="text-[11px] tabular-nums" style={{ color: isImprovement ? 'oklch(0.55 0.14 145)' : 'oklch(0.6 0.18 25)' }}>{m.delta >= 0 ? '+' : ''}{m.delta.toFixed(1)}%</div>
            </div>
            <div className="text-[18px] tabular-nums font-medium">{m.format(m.value)}</div>
            <svg width={120} height={40} className="mt-1">
              <path d={path} stroke="oklch(0.55 0.005 250)" strokeWidth="1.25" fill="none" />
              <circle cx={120} cy={40 - (m.trend[m.trend.length - 1] - min) / range * 40} r={2.5} fill="oklch(0.55 0.18 250)" />
            </svg>
          </button>
        );
      })}
    </div>
  );
}

// NewFeatureBadge.tsx
import { useState, useEffect } from 'react';
const KEY = 'new-feature-dismissed-v1';
export function NewFeatureBadge({ featureId, launchedAt, children, description }: { featureId: string; launchedAt: number; children: React.ReactNode; description: string }) {
  const [dismissed, setDismissed] = useState<boolean>(() => { try { return JSON.parse(localStorage.getItem(KEY) ?? '[]').includes(featureId); } catch { return false; } });
  const isStillNew = Date.now() - launchedAt < 14 * 86400_000;
  const show = !dismissed && isStillNew;
  const onActivate = () => { setDismissed(true); try { const arr = JSON.parse(localStorage.getItem(KEY) ?? '[]'); if (!arr.includes(featureId)) localStorage.setItem(KEY, JSON.stringify([...arr, featureId])); } catch {} };
  if (!show) return <>{children}</>;
  return (
    <span className="relative inline-flex items-center" onClick={onActivate}>
      {children}
      <span className="ml-1 text-[9px] uppercase tracking-wider bg-[oklch(0.55_0.18_250)] text-white px-1 py-0.5 rounded" title={description}>NEW</span>
    </span>
  );
}
